    int i, j;

    for (i = 0; i < PSINN_N; i++) {
        const float a = (psinn_fc1_1_w[i] * psinn_fc1_1_w_s) * t + psinn_fc1_1_b[i];
        const float b = (psinn_fc1_3_w[i] * psinn_fc1_3_w_s) * x;
        u1_1[i] = tanhf(a + b);
        u1_2[i] = tanhf(a - b);
    }
    for (j = 0; j < PSINN_N; j++) {
        float s1 = 0.0f, s2 = 0.0f, s3 = 0.0f;
        for (i = 0; i < PSINN_N; i++) {
            const float a1 = (psinn_fc2_1_w[i * PSINN_N + j] * psinn_fc2_1_w_s);
            const float a2 = (psinn_fc2_2_w[i * PSINN_N + j] * psinn_fc2_2_w_s);
            const float a3 = (psinn_fc2_3_w[i * PSINN_N + j] * psinn_fc2_3_w_s);
            s1 += u1_1[i] * a1 + u1_2[i] * a3;
            s2 += u1_1[i] * a3 + u1_2[i] * a1;
            s3 += (u1_1[i] - u1_2[i]) * a2;
        }
        const float bb = psinn_fc2_1_b[j] + psinn_fc2_3_b[j];
        u2_1[j] = tanhf(s1 + bb);
        u2_2[j] = tanhf(s2 + bb);
        u2_3[j] = tanhf(s3);
    }
    for (j = 0; j < 2 * PSINN_N; j++) {
        float s = 0.0f;
        for (i = 0; i < PSINN_N; i++) {
            s += (u2_1[i] - u2_2[i]) * (psinn_fc3_1_w[i * 2 * PSINN_N + j] * psinn_fc3_1_w_s);
            s += u2_3[i] * (psinn_fc3_2_w[i * 2 * PSINN_N + j] * psinn_fc3_2_w_s);
        }
        u3_1[j] = tanhf(s);
    }
